  ('fire-eq-tech-moex-02967', 'fire-eq-tech', 'fire-eq-tech-moex-098-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '有關火災輻射熱的特性敘述，何者正確？', '["輻射熱量約為燃燒物總發熱量之70%", "受輻射物體熱量隨著輻射角度增大而變大", "輻射熱為一種電磁波，其波長範圍約為0.4~100μm", "高10 m之兩層建築，若兩建築物外壁皆為木板壁，在火焰寬8 m時，其防止輻射熱延燒之安全距離至少應在12 m 以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:26+00:00", "source_pdf_sha1": "b33459e35331", "answer_pdf_sha1": "45db166de921", "source_family": "moex-gov-tw", "moex": {"exam_code": "098220", "c": "902", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "火災學概要", "year": "098", "exam_name": "098年建築師、技師、消防設備師、不動產經紀人、記帳士、第二次消防設備士、語言治療師", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
